```plantuml
@startuml
abstract class BookFactory {
  +GetBook()
}

class FantasticFactory {
  -_page
  -_author
  +FantasticFactory()
}

class ScienceFictionFactory {
  -_page
  -_author
  +ScienceFictionFactory()
}

abstract class Book {
  +BookCategory
  +Page
  +Author
}

class FantasticBook {
  -_bookCategory
  -_page
  -_author
  +FantasticBook()
}

class ScienceFictionBook {
  -_bookCategory
  -_page
  -_author
  +ScienceFictionBook()
}

FantasticFactory -up-|> BookFactory
ScienceFictionFactory -up-|> BookFactory

FantasticBook -up-|> Book
ScienceFictionBook -up-|> Book

FantasticFactory ..> FantasticBook
ScienceFictionFactory ..> ScienceFictionBook
@enduml
```
